mapper.select:
SELECT COUNT(*)
FROM DAILY_TASK_LOG
WHERE TASK_NO       = #{taskNo}
  AND EMP_NO        = #{empNo}
  AND DEL_YN        = 'N'
  AND TRUNC(WORK_DTM) = TRUNC(SYSDATE)

mapper.update:
UPDATE DAILY_TASK_LOG
SET
    DEL_YN  = 'Y',
    DEL_DTM = SYSDATE
WHERE TASK_LOG_NO = #{taskLogNo}
  AND EMP_NO      = #{empNo}
